import { useCallback } from "react";
import type { ApiClientError } from "@workspace/api-client/types";
import { logApiErrorToRollbar, logErrorToRollbar } from "./rollbar";

/**
 * Hook to create error handlers that automatically log to Rollbar
 *
 * @example
 * ```tsx
 * const { handleApiError } = useRollbarErrorHandler();
 *
 * const { mutate } = useCreatePaymentMethod({
 *   onError: (error) => {
 *     handleApiError(error, { paymentMethod: 'credit_card' });
 *     toast.error(error.message);
 *   }
 * });
 * ```
 */
export const useRollbarErrorHandler = () => {
  const handleApiError = useCallback(
    (error: ApiClientError, context?: Record<string, unknown>) => {
      logApiErrorToRollbar(error, context);
    },
    [],
  );

  const handleError = useCallback(
    (error: Error | string, context?: Record<string, unknown>) => {
      logErrorToRollbar(error, context);
    },
    [],
  );

  return {
    handleApiError,
    handleError,
  };
};

