import Rollbar from "rollbar";

// Check if Rollbar should be enabled
export const isRollbarEnabled =
  import.meta.env.PROD && !!import.meta.env.VITE_ROLLBAR_ACCESS_TOKEN;

const MAX_SERIALIZED_PAYLOAD_LENGTH = 1000;

const serializeResponsePayload = (data: unknown) => {
  if (data == null) {
    return undefined;
  }

  try {
    const serialized = JSON.stringify(data);

    if (serialized.length > MAX_SERIALIZED_PAYLOAD_LENGTH) {
      return `${serialized.slice(0, MAX_SERIALIZED_PAYLOAD_LENGTH)}…`;
    }

    return serialized;
  } catch {
    return "[unserializable]";
  }
};

const rollbarConfig: Rollbar.Configuration = {
  accessToken: import.meta.env.VITE_ROLLBAR_ACCESS_TOKEN || "disabled",
  captureUncaught: true,
  captureUnhandledRejections: true,
  enabled: isRollbarEnabled,
  environment: import.meta.env.MODE || "development",
  payload: {
    client: {
      javascript: {
        code_version: import.meta.env.VITE_APP_VERSION || "unknown",
        source_map_enabled: true,
      },
    },
    environment: import.meta.env.MODE || "development",
  },
};

export const rollbar = new Rollbar(rollbarConfig);

// Helper function to log errors to Rollbar
export const logErrorToRollbar = (
  error: Error | string,
  customData?: Record<string, unknown>,
) => {
  if (isRollbarEnabled) {
    rollbar.error(error, customData);
  } else {
    // In development, log to console
    console.error("Error:", error, customData);
  }
};

// Helper function to log API errors specifically
export const logApiErrorToRollbar = (
  error: {
    message?: string;
    response?: {
      status?: number;
      statusText?: string;
      data?: unknown;
    };
    type?: string;
  },
  context?: Record<string, unknown>,
) => {
  const customData: Record<string, unknown> = {
    apiError: true,
    errorMessage: error.message,
    errorType: error.type,
    responseData: serializeResponsePayload(error.response?.data),
    responseStatus: error.response?.status,
    responseStatusText: error.response?.statusText,
    ...context,
  };

  if (!(error instanceof Error)) {
    customData.rawError = error;
  }

  const rollbarError =
    error instanceof Error
      ? error
      : new Error(error.message || "Unknown API error");

  logErrorToRollbar(rollbarError, customData);
};

